	}
	retryReq := httptest.NewRequest(http.MethodGet, "/users", nil)
	addAuth(retryReq, auth)
	retryResp, err := app.Test(retryReq, 5000)
	if err != nil {
		t.Fatal(err)
	}
	if retryResp.StatusCode != 200 {
		body, _ := io.ReadAll(retryResp.Body)
