	if err != nil {
		t.Fatal(err)
	}
	if _, err := finance.RequestBudgetChange(bID, 1, 1200, "too large", "admin", nil); err == nil {
		t.Fatalf("expected >10%% admin change to be rejected")
	}
}

func TestBudgetChangeOverTenPercentRejectsTeamLeadRequester(t *testing.T) {
	st := setupStore(t)
