	}
	body, _ := io.ReadAll(resp.Body)
	if resp.StatusCode != 200 || !strings.Contains(string(body), "/api/auth/admin-reset") {
		t.Fatalf("expected users page to include admin reset form, got %d body=%s", resp.StatusCode, string(body))
	}
}

